fun themeById(id: String): ThemeConfig = themes.firstOrNull { it.id == id } ?: themes.first() }
fun WinningGender.opposite(): WinningGender = if (this == WinningGender.BOY) WinningGender.GIRL else WinningGender.BOY
private fun decorationSpec( type: ThemeDecoration, xFraction: Float, yFraction: Float, size: Dp, durationMillis: Int, driftX: Dp, driftY: Dp, minAlpha: Float, maxAlpha: Float, motion: ThemeMotion = ThemeMotion.DRIFT, phaseOffset: Float = 0f, mirrorHorizontally: Boolean = false, rotationDegrees: Float = 0f ): ThemeDecorationSpec = ThemeDecorationSpec( type = type, xFraction = xFraction, yFraction = yFraction, size = size, durationMillis = durationMillis, driftX = driftX, driftY = driftY, minAlpha = minAlpha, maxAlpha = maxAlpha, motion = motion, phaseOffset = phaseOffset, mirrorHorizontally = mirrorHorizontally, rotationDegrees = rotationDegrees )

