@Composable internal fun GameScreen( setup: RevealSetupConfig, gameState: GameState, onCardClick: (RevealCard) -> Unit, onRestart: () -> Unit ) { val remainingCount = gameState.cards.size - gameState.revealedCount
Box( modifier = Modifier .fillMaxSize() .background(setup.theme.backgroundBrush()) ) { AnimatedDecorationLayer(theme = setup.theme) Box( modifier = Modifier .fillMaxSize() .background( Brush.verticalGradient( listOf( Color.White.copy(alpha = 0.07f), Color.Transparent, Color.White.copy(alpha = 0.05f) ) ) ) ) Column( modifier = Modifier .fillMaxSize() .statusBarsPadding() .navigationBarsPadding() .padding(horizontal = 20.dp, vertical = 18.dp) ) { PlayfulMomentHeader( modifier = Modifier .fillMaxWidth() .testTag(TestTags.GameHeader), eyebrow = stringResource(R.string.gameplay_header_eyebrow), title = setup.boardHeaderMessage.title, subtitle = setup.boardHeaderMessage.subtitle, theme = setup.theme ) Box( modifier = Modifier .fillMaxWidth() .weight(1f), contentAlignment = Alignment.Center ) { Column( modifier = Modifier.widthIn(max = 460.dp), horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.spacedBy(18.dp) ) { BoardPanel( theme = setup.theme, cards = gameState.cards, onCardClick = onCardClick ) RemainingCounter( revealedGenders = gameState.revealedGenders, boyRevealedCount = gameState.boyRevealedCount, girlRevealedCount = gameState.girlRevealedCount, hiddenCount = remainingCount, theme = setup.theme ) } } }
if (gameState.celebrationVisible) { CelebrationOverlay(setup = setup, onRestart = onRestart) } } }
@Composable private fun BoardPanel( theme: ThemeConfig, cards: List<RevealCard>, onCardClick: (RevealCard) -> Unit ) { val boardShape = RoundedCornerShape(42.dp)
BoxWithConstraints( modifier = Modifier .fillMaxWidth() .testTag(TestTags.GameBoard), contentAlignment = Alignment.Center ) { val boardSize = maxWidth.coerceAtMost(408.dp) Box( modifier = Modifier .size(boardSize) .shadow(28.dp, boardShape, clip = false) .clip(boardShape) .background(theme.boardPanelBrush()) .border(10.dp, Color.White.copy(alpha = 0.92f), boardShape) .border(1.5.dp, theme.boardStrokeColor.copy(alpha = 0.9f), boardShape) ) { Canvas(modifier = Modifier.matchParentSize()) { drawRoundRect( color = theme.boardStrokeColor.copy(alpha = 0.15f), topLeft = androidx.compose.ui.geometry.Offset(size.width * 0.06f, size.height * 0.06f), size = androidx.compose.ui.geometry.Size(size.width * 0.88f, size.height * 0.88f), cornerRadius = androidx.compose.ui.geometry.CornerRadius(44.dp.toPx(), 44.dp.toPx()) ) drawLine( color = Color.White.copy(alpha = 0.65f), start = androidx.compose.ui.geometry.Offset(size.width * 0.1f, size.height * 0.12f), end = androidx.compose.ui.geometry.Offset(size.width * 0.9f, size.height * 0.32f), strokeWidth = 6.dp.toPx() ) } Column( modifier = Modifier .fillMaxSize() .aspectRatio(1f) .padding(20.dp), verticalArrangement = Arrangement.spacedBy(14.dp) ) { cards.chunked(3).forEach { rowCards -> Row( modifier = Modifier.weight(1f), horizontalArrangement = Arrangement.spacedBy(14.dp) ) { rowCards.forEach { card -> RevealCardView( theme = theme, card = card, labelTag = TestTags.boardCardLabel(card.id), modifier = Modifier .weight(1f) .fillMaxSize(), onClick = { onCardClick(card) } ) } } } } } } }
@Composable private fun RevealCardView( theme: ThemeConfig, card: RevealCard, labelTag: String, modifier: Modifier = Modifier, onClick: () -> Unit ) { val interactionSource = remember { MutableInteractionSource() } val isPressed by interactionSource.collectIsPressedAsState() val rotation = animateFloatAsState( targetValue = if (card.isRevealed) 180f else 0f, animationSpec = tween(durationMillis = 820, easing = FastOutSlowInEasing), label = "card-rotation" ) val scale = animateFloatAsState( targetValue = when { isPressed && !card.isRevealed -> 0.95f card.isRevealed -> 1.02f else -> 1f }, animationSpec = spring(dampingRatio = 0.62f, stiffness = 320f), label = "card-scale" )
Box( modifier = modifier .testTag(TestTags.boardCard(card.id)) .graphicsLayer { scaleX = scale.value scaleY = scale.value rotationY = rotation.value cameraDistance = 18f * density } .clip(CircleShape) .clickable( enabled = !card.isRevealed, interactionSource = interactionSource, indication = null, onClick = onClick ), contentAlignment = Alignment.Center ) { if (rotation.value <= 90f) { CircularFace( brush = Brush.linearGradient( listOf( Color.White, theme.boardFrameColor.copy(alpha = 0.94f), Color.White.copy(alpha = 0.98f) ) ), borderColor = Color.White.copy(alpha = 0.94f), rimColor = theme.boardStrokeColor.copy(alpha = 0.46f), label = "?", labelTag = labelTag, textColor = theme.celebrationAccent ) } else { val revealedGender = requireNotNull(card.gender) CircularFace( modifier = Modifier.graphicsLayer { rotationY = 180f }, brush = Brush.linearGradient(revealedGender.cardBrush()), borderColor = Color.White.copy(alpha = 0.9f), rimColor = revealedGender.accentColor().copy(alpha = 0.72f), label = stringResource(revealedGender.labelResId()), labelTag = labelTag, textColor = revealedGender.revealTextColor() ) } } }
