private fun WinningGender.cardBrush(): List<Color> = if (this == WinningGender.BOY) { listOf(Color(0xFFEAF8FF), Color(0xFFBAE6FD), Color(0xFFE7F7FF)) } else { listOf(Color(0xFFFFF0F7), Color(0xFFFBCFE8), Color(0xFFFFE6F1)) }
private fun WinningGender.revealTextColor(): Color = if (this == WinningGender.BOY) Color(0xFF0D6990) else Color(0xFFAD3C73)

